text:
{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI Theme Package Release Readiness",
    "participants": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "decisions": {
      "confirmed_decisions": [
        {
          "topic": "공개 릴리스 목표 시점",
          "decision": "스모크 테스트가 통과할 경우 공개 릴리스 목표는 금요일 15:00 KST이다.",
          "conditions": [
            "스모크 테스트 통과 시"
          ]
        },
        {
          "topic": "packageName mismatch 대응",
          "decision": "packageName mismatch가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토를 진행한다."
        }
      ],
      "rejected_proposals": [
        {
          "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경하자",
          "result": "기각"
        }
      ],
      "internal_stretch_goals": [
        {
          "goal": "수요일 릴리스",
          "status": "내부 스트레치 골",
          "note": "확정 공개 일정이 아니다."
        }
      ]
    },
    "non_decisions": [
      {
        "topic": "README 설치 절차 검토",
        "note": "목요일까지 가능하면 검토하자는 제안은 있었으나 담당자는 정해지지 않았다."
      },
      {
        "topic": "릴리스 노트에 수요일 내부 스트레치 골 언급 여부",
        "note": "논의되었으나 결론이 나지 않았다."
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로가 릴리스를 지연시킬 수 있다."
      },
      {
        "risk": "README 설치 절차가 오래된 상태라면 릴리스 노트가 사용자를 오도할 수 있다."
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 골을 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "명시적으로 확인됨"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 failure triage note를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "명시적으로 확인됨"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 후 생성된 tarball 경로를 확인한다.",
      "due": "미정",
      "status": "확정",
      "source_certainty": "명시적으로 확인됨"
    },
    {
      "owner": null,
      "task": "README 설치 절차를 가능하면 목요일까지 검토한다.",
      "due": "목요일 가능 시",
      "status": "미배정 제안",
      "source_certainty": "제안은 있었으나 담당자 미지정"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "Minjun의 스모크 테스트 결과가 금요일 10:00 KST까지 공유되었는지 확인",
      "스모크 테스트 통과 여부에 따라 금요일 15:00 KST 공개 릴리스 조건이 충족되는지 확인",
      "Doyun의 failure triage note가 금요일 12:00 KST까지 action_items.md에 반영되었는지 확인",
      "스모크 결과 공유 이후 Hara의 tarball 경로 점검 결과를 확인",
      "README 설치 절차 검토 담당자 지정 필요 여부를 확인",
      "최종 릴리스 승인 권한자와 릴리스 노트의 수요일 스트레치 골 언급 여부를 후속 결정 사항으로 추적"
    ],
    "what_not_to_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구사항",
      "지정되지 않은 담당자",
      "명시되지 않은 마감일",
      "확정되지 않은 승인 권한자"
    ]
  },
  "non_invention_rules": [
    "회의 메모에 없는 고객, 예산, 보안, 장애, 법무 사실을 추가하지 않는다.",
    "담당자가 명시되지 않은 항목에 임의로 owner를 부여하지 않는다.",
    "마감이 없는 항목에 임의의 due를 추가하지 않는다.",
    "수요일 일정은 내부 스트레치 골로만 기록하고 확정 공개 일정으로 서술하지 않는다.",
    "기각된 제안은 확정 결정처럼 서술하지 않는다.",
    "오픈 질문은 답이 정해진 것처럼 서술하지 않는다."
  ]
}
